func solve(grid [][]int64, x int64, y int64, k int64) [][]int64 {
    m := len(grid)
    if m == 0 {
        return grid
    }
    n := len(grid[0])

    // Create a copy of the grid
    copiedGrid := make([][]int64, m)
    for i := 0; i < m; i++ {
        copiedGrid[i] = make([]int64, n)
        copy(copiedGrid[i], grid[i])
    }

    xInt := int(x)
    yInt := int(y)
    kInt := int(k)

    // Extract the submatrix rows and columns
    rowsToReverse := make([][]int64, kInt)
    for i := 0; i < kInt; i++ {
        row := copiedGrid[xInt+i]
        subRow := make([]int64, kInt)
        for j := 0; j < kInt; j++ {
            subRow[j] = row[yInt+j]
        }
        rowsToReverse[i] = subRow
    }

    // Reverse the rows of the submatrix
    reversedRows := make([][]int64, kInt)
    for i := 0; i < kInt; i++ {
        reversedRows[i] = rowsToReverse[kInt-1-i]
    }

    // Assign the reversed rows back to the copied grid
    for i := 0; i < kInt; i++ {
        copiedGrid[xInt+i] = reversedRows[i]
    }

    return copiedGrid
}
